days.setup_script:
mkdir -p terraform-demo && cd terraform-demo
cat << 'EOF' > main.tf
terraform {
  required_providers {
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
  }
}
resource "local_file" "welcome" {
  filename = "${path.module}/welcome.txt"
  content  = "Welcome to Terraform Practice on KillerCoda!"
}
EOF
clear
echo 'Terraform configuration main.tf generated inside terraform-demo/'
